#include <stdio.h>
#include <stdlib.h>

// Structure for priority queue
typedef struct Node {
    int elevation;
    int row;
    int col;
    struct Node* next;
} Node;

// Function to create a new node
Node* createNode(int elevation, int row, int col) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->elevation = elevation;
    newNode->row = row;
    newNode->col = col;
    newNode->next = NULL;
    return newNode;
}

// Function to insert a node into the priority queue
void insertNode(Node** head, int elevation, int row, int col) {
    Node* newNode = createNode(elevation, row, col);
    if (*head == NULL || (*head)->elevation > newNode->elevation) {
        newNode->next = *head;
        *head = newNode;
    } else {
        Node* current = *head;
        while (current->next != NULL && current->next->elevation < newNode->elevation) {
            current = current->next;
        }
        newNode->next = current->next;
        current->next = newNode;
    }
}

// Function to delete a node from the priority queue
Node* deleteNode(Node** head) {
    Node* temp = *head;
    *head = (*head)->next;
    return temp;
}

// Function to find the minimum time to reach the bottom-right cell
int swimInWater(int** grid, int gridSize) {
    int n = gridSize;
    int** visited = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        visited[i] = (int*)malloc(n * sizeof(int));
    }
    Node* head = NULL;
    insertNode(&head, grid[0][0], 0, 0);
    visited[0][0] = 1;
    int dirs[][2] = {{0, 1}, {1, 0}, {0, -1}, {-1, 0}};
    while (head != NULL) {
        Node* current = deleteNode(&head);
        int elevation = current->elevation;
        int row = current->row;
        int col = current->col;
        if (row == n - 1 && col == n - 1) {
            return elevation;
        }
        for (int i = 0; i < 4; i++) {
            int nr = row + dirs[i][0];
            int nc = col + dirs[i][1];
            if (nr >= 0 && nc >= 0 && nr < n && nc < n && !visited[nr][nc]) {
                visited[nr][nc] = 1;
                insertNode(&head, (grid[nr][nc] > elevation) ? grid[nr][nc] : elevation, nr, nc);
            }
        }
        free(current);
    }
    return -1;
}

int main() {
    int gridSize = 2;
    int** grid = (int**)malloc(gridSize * sizeof(int*));
    for (int i = 0; i < gridSize; i++) {
        grid[i] = (int*)malloc(gridSize * sizeof(int));
    }
    grid[0][0] = 0;
    grid[0][1] = 2;
    grid[1][0] = 1;
    grid[1][1] = 3;
    printf("Minimum time to reach destination: %d\n", swimInWater(grid, gridSize));
    return 0;
}

